import asyncio
import websockets
import json
from collections import defaultdict

class GameServer:
    def __init__(self):
        self.connected_players = {}
        self.player_inventory = defaultdict(lambda: defaultdict(int))

    async def register(self, websocket):
        self.connected_players[websocket] = None

    async def unregister(self, websocket):
        del self.connected_players[websocket]

    async def handle_trade(self, player_id, target_id, item, quantity):
        if player_id not in self.player_inventory or self.player_inventory[player_id][item] < quantity:
            return {"status": "error", "message": "Insufficient items."}
        
        # Execute trade
        self.player_inventory[player_id][item] -= quantity
        self.player_inventory[target_id][item] += quantity

        return {"status": "success", "message": f"Traded {quantity} of {item} to {target_id}."}

    async def process_message(self, websocket, message):
        data = json.loads(message)
        action = data.get("action")
        player_id = data.get("player_id")

        if action == "register":
            self.player_inventory[player_id] = defaultdict(int)
            self.connected_players[websocket] = player_id
            return {"status": "registered", "player_id": player_id}

        elif action == "trade":
            target_id = data.get("target_id")
            item = data.get("item")
            quantity = data.get("quantity")
            response = await self.handle_trade(player_id, target_id, item, quantity)
            return response

    async def handle_connection(self, websocket, path):
        await self.register(websocket)
        try:
            async for message in websocket:
                response = await self.process_message(websocket, message)
                await websocket.send(json.dumps(response))
        finally:
            await self.unregister(websocket)

    async def main(self):
        async with websockets.serve(self.handle_connection, "localhost", 6789):
            await asyncio.Future()  # Run forever

if __name__ == "__main__":
    server = GameServer()
    asyncio.run(server.main())